/// Look up a Korean character's bitmap data
fn find_glyph(ch: char) -> Option<&'static [u8; 32]> {
    for (c, bitmap) in GLYPH_DATA {
        if *c == ch {
            return Some(bitmap);
        }
    }
    None
}

/// Draw a single Korean glyph at the given position (top-left corner).
/// Returns the width consumed (16 for Korean glyphs, or 0 if not found).
fn draw_korean_glyph<D: DrawTarget<Color = BinaryColor>>(
    display: &mut D,
    ch: char,
    pos: Point,
) -> u32 {
    if let Some(bitmap) = find_glyph(ch) {
        for row in 0..GLYPH_HEIGHT {
            let byte_hi = bitmap[(row * 2) as usize];
            let byte_lo = bitmap[(row * 2 + 1) as usize];
            for col in 0..8u32 {
                if byte_hi & (0x80 >> col) != 0 {
                    let _ = Pixel(
                        Point::new(pos.x + col as i32, pos.y + row as i32),
                        BinaryColor::On,
                    )
                    .draw(display);
                }
            }
            for col in 0..8u32 {
                if byte_lo & (0x80 >> col) != 0 {
                    let _ = Pixel(
                        Point::new(pos.x + 8 + col as i32, pos.y + row as i32),
                        BinaryColor::On,
                    )
                    .draw(display);
                }
            }
        }
        GLYPH_WIDTH
    } else {
        0
    }
}

/// Draw mixed Korean + ASCII text.
/// Korean characters use 16x16 bitmaps, ASCII uses the provided MonoFont.
/// `pos` is the top-left corner for the text baseline alignment.
/// `baseline_y` is the y coordinate for the text baseline (for ASCII font alignment).
pub fn draw_korean_text<D: DrawTarget<Color = BinaryColor>>(
    display: &mut D,
    text: &str,
    pos: Point,
    ascii_font: &MonoFont,
) {
    let style = MonoTextStyle::new(ascii_font, BinaryColor::On);
    let ascii_char_width = ascii_font.character_size.width as i32;

    let mut cursor_x = pos.x;
    // Korean glyphs are drawn from top-left at pos.y.
    // ASCII Text::new uses baseline positioning.
    // To align tops: ascii_baseline = pos.y + font.baseline
    let ascii_baseline_y = pos.y + ascii_font.baseline as i32;
    // Korean glyphs: top-aligned to pos.y, height=16

    let mut ascii_buf = [0u8; 4];
    for ch in text.chars() {
        if find_glyph(ch).is_some() {
            // Draw Korean glyph (top-left aligned)
            draw_korean_glyph(display, ch, Point::new(cursor_x, pos.y));
            cursor_x += GLYPH_WIDTH as i32;
        } else {
            // Draw ASCII character using embedded_graphics Text
            let s = ch.encode_utf8(&mut ascii_buf);
            let _ = Text::new(s, Point::new(cursor_x, ascii_baseline_y), style).draw(display);
            cursor_x += ascii_char_width;
        }
    }
}

/// Measure the pixel width of mixed Korean/ASCII text (using 12pt ASCII = 7px per char)
pub fn measure_korean_text(text: &str) -> u32 {
    let mut w: u32 = 0;
    for ch in text.chars() {
        if find_glyph(ch).is_some() {
            w += GLYPH_WIDTH;
        } else {
            w += 7; // PROFONT_12_POINT char width
        }
    }
    w
}

/// Map OpenWeatherMap "main" field to Korean description
pub fn weather_to_korean(main: &str) -> &str {
    match main {
        "Clear" => "맑음",
        "Clouds" => "흐림",
        "Rain" => "비",
        "Snow" => "눈",
        "Mist" => "박무",
        "Fog" => "안개",
        "Haze" => "연무",
        "Drizzle" => "이슬비",
        "Thunderstorm" => "뇌우",
        _ => main,
    }
}

/// Map weekday number (0=Sun) to Korean single character
pub fn weekday_korean(weekday: u8) -> &'static str {
    match weekday {
        0 => "일",
        1 => "월",
        2 => "화",
        3 => "수",
        4 => "목",
        5 => "금",
        6 => "토",
        _ => "?",
    }
}
